+    @Reflect
+    public static void flashAttentionF16(@RO KernelContext kernelContext,
+                                      @RO F16Array Q, @RO F16Array K, @RO F16Array V,
+                                      @WO F16Array O, @RW F16Array m, @RW F16Array l,
